export default function Portfolio() {
  const navigate = useNavigate();
  return (
    <div style={{ background: "#EAEDFB", minHeight: "100vh" }}>
      <Header />
      <TopNavBar />
      <div style={{ maxWidth: 470, margin: "0 auto", position: "relative" }}>
        {/* Back navigation */}
        <button
          onClick={() => navigate(-1)}
          style={{
            position: "absolute",
            top: 10,
            left: -48,
            background: "none",
            border: "none",
            fontSize: 30,
            cursor: "pointer",
          }}
        >
          <FiChevronLeft />
        </button>
        {/* Main Card */}
        <div
          style={{
            background: "#F3F6FC",
            borderRadius: 32,
            padding: 18,
            margin: "40px 0 0 0",
            boxShadow: "0 2px 18px #b8bee330",
          }}
        >
          {/* Search */}
          <div
            style={{
              background: "#fff",
              borderRadius: 14,
              padding: "9px 12px 9px 0",
              marginBottom: 22,
              display: "flex",
              alignItems: "center",
            }}
          >
            <FiSearch style={{ marginLeft: 15, color: "#AAA", fontSize: 18 }} />
            <input
              placeholder="Search name, keyword..."
              style={{
                width: "100%",
                border: "none",
                fontSize: 17,
                outline: "none",
                background: "transparent",
                marginLeft: 8,
              }}
            />
          </div>
          {/* Available Amount + Debt */}
          <div
            style={{
              background: "#fff",
              borderRadius: 16,
              padding: 16,
              marginBottom: 16,
              display: "flex",
              flexDirection: "column",
              gap: 6,
            }}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                paddingBottom: 4,
              }}
            >
              <div>
                <div style={{ color: "#9797a0", fontSize: 14 }}>
                  Available amount
                </div>
                <div
                  style={{ color: "#51A654", fontWeight: 700, fontSize: 20 }}
                >
                  ₹ 45,987.15
                </div>
                <span
                  style={{
                    color: "#5D5FEF",
                    fontSize: 13,
                    cursor: "pointer",
                  }}
                >
                  View history
                </span>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ color: "#9797a0", fontSize: 14 }}>
                  Total dept taken
                </div>
                <div
                  style={{ color: "#E84D4F", fontWeight: 700, fontSize: 20 }}
                >
                  ₹ 30,000.00
                </div>
                <button
                  style={{
                    background: "#5D5FEF",
                    color: "#fff",
                    border: "none",
                    borderRadius: 11,
                    padding: "5px 15px",
                    fontWeight: 600,
                    fontSize: 13,
                    marginTop: 7,
                    cursor: "pointer",
                  }}
                >
                  All times
                </button>
              </div>
            </div>
          </div>
          {/* Payments Due Progress */}
          <PaymentsDueCard
            paidAmount={26000}
            totalAmount={34000}
            paidBills={4}
            allBills={11}
            toPay={8000}
            avatars={[
              "https://randomuser.me/api/portraits/men/11.jpg",
              "https://randomuser.me/api/portraits/men/13.jpg",
              "https://randomuser.me/api/portraits/women/18.jpg",
            ]}
          />
          {/* Pie Chart & Investor Contribution */}
          <div
            style={{
              background: "#fff",
              borderRadius: 16,
              padding: 18,
              marginBottom: 22,
            }}
          >
            <div
              style={{
                color: "#9797a0",
                fontSize: 14,
                marginBottom: 9,
                fontWeight: 600,
              }}
            >
              Investor Contribution
            </div>
            <div
              style={{ display: "flex", alignItems: "center", marginBottom: 9 }}
            >
              <PieChart data={investorData} />
              <div
                style={{
                  fontWeight: 700,
                  fontSize: 20,
                  color: "#294286",
                  marginLeft: 24,
                }}
              >
                ₹ 10,00,000
                <div style={{ fontSize: 14, color: "#676f8a", marginTop: 2 }}>
                  Total Investment
                </div>
              </div>
            </div>
            {/* Investor legend */}
            <div style={{ fontSize: 14, color: "#444" }}>
              {investorData.map((inv, i) => (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    marginBottom: 1,
                  }}
                >
                  <span
                    style={{
                      display: "inline-block",
                      width: 13,
                      height: 13,
                      borderRadius: "50%",
                      background: inv.color,
                      marginRight: 8,
                    }}
                  />
                  {inv.name}{" "}
                  <b style={{ marginLeft: 5 }}>{`₹${(inv.amount / 1000).toFixed(
                    0
                  )}K`}</b>{" "}
                  ({Math.round((inv.amount / totalInvestment) * 100)}%)
