              ))}
              <div style={{ display: "flex", alignItems: "center" }}>
                <span
                  style={{
                    display: "inline-block",
                    width: 13,
                    height: 13,
                    borderRadius: "50%",
                    background: "#BFBFBF",
                    marginRight: 8,
                  }}
                />
                Others <b style={{ marginLeft: 5 }}>₹400K</b> (40%)
              </div>
            </div>
            <div style={{ textAlign: "right" }}>
              <span
                style={{
                  color: "#5D5FEF",
                  fontWeight: 600,
                  cursor: "pointer",
                  fontSize: 15,
                }}
              >
                View All
              </span>
            </div>
          </div>
          {/* Investor Performance Table */}
          <div
            style={{
              background: "#fff",
              borderRadius: 14,
              padding: 18,
              marginBottom: 22,
              boxShadow: "0 1px 5px #d1d8ed21",
            }}
          >
            <div style={{ fontWeight: 600, color: "#222", marginBottom: 6 }}>
              Investor Performance
            </div>
            {performance.map((inv, i) => (
              <div
                key={i}
                style={{
                  display: "flex",
                  alignItems: "center",
                  marginBottom: 9,
                }}
              >
                <div style={{ flex: 1 }}>
                  <div
                    style={{
                      fontWeight: 600,
                      color: "#3649ca",
                      marginBottom: 2,
                    }}
                  >
                    {inv.name}
                  </div>
                  <div style={{ fontSize: 12, color: "#acacac" }}>
                    {inv.date}
                  </div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div style={{ fontWeight: 700 }}>{inv.amount}</div>
                  <div style={{ fontSize: 11, color: "#8fadc7" }}>
                    {inv.rate} ({inv.count})
                  </div>
                </div>
              </div>
            ))}
            <div style={{ textAlign: "center" }}>
              <span
                style={{
                  color: "#5D5FEF",
                  fontWeight: 600,
                  cursor: "pointer",
                  fontSize: 14,
                }}
              >
                View All
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// Payments Due Section (modular for reusability)
function PaymentsDueCard({
  paidAmount,
  totalAmount,
  paidBills,
  allBills,
  toPay,
  avatars,
}) {
  const percent = Math.round((paidAmount / totalAmount) * 100);
  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: 18,
        marginBottom: 18,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        gap: 14,
        boxShadow: "0 1px 5px #e5e5f739",
      }}
    >
      <div style={{ width: 110 }}>
        <svg width="90" height="90" viewBox="0 0 36 36">
          <circle
            cx="18"
            cy="18"
            r="15.5"
            fill="#F8FAFF"
            stroke="#EAEDFB"
            strokeWidth="3"
          />
          <circle
            cx="18"
            cy="18"
            r="15.5"
            fill="none"
            stroke="#5D5FEF"
            strokeWidth="3"
            strokeDasharray={`${percent * 1.8} 100`}
            transform="rotate(-90 18 18)"
          />
          <text
            x="18"
            y="21"
            textAnchor="middle"
            fontWeight="bold"
            fontSize="16"
            fill="#5D5FEF"
          >
            {percent}%
          </text>
        </svg>
        <div
          style={{
            textAlign: "center",
            fontSize: 12,
            color: "#8fadc7",
            margin: "8px 0 0 0",
          }}
        >
          Interest Paid
        </div>
      </div>
      <div style={{ flex: 1 }}>
        <div
          style={{
            fontWeight: 600,
            fontSize: 16,
            color: "#222",
            marginBottom: 1,
          }}
        >
          Paid amount
        </div>
        <div style={{ fontSize: 14, color: "#555", marginBottom: 3 }}>
          <b style={{ color: "#3649ca" }}>₹{paidAmount.toLocaleString()}</b> / ₹
          {totalAmount.toLocaleString()}
        </div>
        <div style={{ fontSize: 13, color: "#8590B0", marginBottom: 4 }}>
          Paid bills {paidBills} / {allBills}
        </div>
        <div
          style={{
            fontWeight: 700,
            color: "#E84D4F",
            fontSize: 15,
            marginBottom: 8,
          }}
        >
          To pay ₹{toPay.toLocaleString()}
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: -14,
            marginBottom: 7,
          }}
        >
          {(avatars.length
            ? avatars
            : [
                "https://randomuser.me/api/portraits/men/11.jpg",
                "https://randomuser.me/api/portraits/men/13.jpg",
                "https://randomuser.me/api/portraits/women/18.jpg",
              ]
          ).map((src, i) => (
            <img
              key={i}
              src={src}
              alt=""
              style={{
                width: 26,
                height: 26,
                borderRadius: "50%",
                border: "2px solid #fff",
                marginLeft: i === 0 ? 0 : -13,
                boxShadow: "0 2px 8px #dbe3f350",
              }}
            />
          ))}
        </div>
        <a
          href="#"
          style={{
            color: "#5D5FEF",
            fontWeight: 600,
            fontSize: 15,
            textDecoration: "underline",
          }}
        >
          View investor performance
        </a>
      </div>
    </div>
  );
}

// Pie Chart SVG (static, tweak as needed)
function PieChart({ data }) {
  return (
    <svg width={80} height={80} viewBox="0 0 36 36" style={{ marginRight: 5 }}>
      <circle
        cx="18"
        cy="18"
        r="16"
        fill="#EAEDFB"
        stroke="#EAEDFB"
        strokeWidth="4"
      />
      <path
        d="M18 2
           A 16 16 0 0 1 34 18"
        fill="none"
        stroke={data[0].color}
        strokeWidth="4"
      />
      <path
        d="M34 18
           A 16 16 0 0 1 24.32 32.8"
        fill="none"
        stroke={data[1].color}
        strokeWidth="4"
      />
      <path
        d="M24.32 32.8
           A 16 16 0 0 1 11.68 32.8"
        fill="none"
        stroke={data[2].color}
        strokeWidth="4"
      />
      <path
        d="M11.68 32.8
           A 16 16 0 0 1 2 18"
        fill="none"
        stroke="#bfbfbf"
        strokeWidth="4"
      />
    </svg>
  );
}
